const TRIAL_ID = "parallel_batch_trigger__6z62rdD";

// Child task: accepts a number, waits 2 seconds, returns the number squared
export const childTask = task({
  id: `childTask-${TRIAL_ID}`,
  run: async (payload: { value: number }): Promise<{ squared: number }> => {
    // Wait for 2 seconds
    await wait.for({ seconds: 2 });

    return { squared: payload.value * payload.value };
  },
});

// Parent task: accepts an array of numbers, triggers childTask for each in parallel
// using batch.triggerByTaskAndWait, then returns an array of squared numbers
export const parentTask = task({
  id: `parentTask-${TRIAL_ID}`,
  run: async (payload: { numbers: number[] }): Promise<{ results: number[] }> => {
    // Build the batch items — each item carries { task, payload } as required by V4
    const batchItems = payload.numbers.map((value) => ({
      task: childTask,
      payload: { value },
    }));

    // Trigger all child tasks in parallel and wait for all to complete
    // batch.triggerByTaskAndWait is the supported V4 pattern (NOT Promise.all + triggerAndWait)
    const batchResult = await batch.triggerByTaskAndWait(batchItems);

    // Unwrap each run result and collect the squared values
    const results = batchResult.runs.map((run) => {
      if (!run.ok) {
        throw new Error(
          `childTask failed for run ${run.id}: ${run.error}`
        );
      }
      return run.output.squared;
    });

    return { results };
  },
});

import { defineConfig } from "@trigger.dev/sdk/v3";

export default defineConfig({
  project: "batch-project",
  dirs: ["./trigger"],
  maxDuration: 300, // 5 minutes maximum compute time per task run
});
